const express = require('express');
const redis = require('redis');

const app = express();
const client = redis.createClient();

app.get('/search', (req, res) => {
  const pattern = req.query.pattern;
  if (!pattern) {
    return res.status(400).send('No search pattern provided');
  }

  // Use the KEYS command with user-provided patterns to search the Redis database
  client.keys(pattern, (err, keys) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error searching for keys');
    }

    // Return the list of matching keys to the user
    res.json(keys);
  });
});

app.post('/execute', (req, res) => {
  const command = req.body.command;
  if (!command) {
    return res.status(400).send('No Redis command provided');
  }

  // Execute the user-provided Redis command
  client.execute(command, (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error executing Redis command');
    }

    // Return the result of the command to the user
    res.json(result);
  });
});